challengeFiles.contents:
*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  --dark-grey: #1b1b32;
  --black: #000;
  --white: #fff;
  --golden-yellow: #fecc4c;
  --yellow: #ffcc4c;
  --gold: #feac32;
  --orange: #ffac33;
  --dark-orange: #f89808;
}

body {
  background-color: var(--dark-grey);
  color: var(--white);
}

h1,
#result {
  text-align: center;
}

h1 {
  margin: 10px 0 15px;
}

.story-container {
  margin: auto;
  padding: 10px;
  width: 80%;
  border-style: double;
  border-width: 14px;
  border-color: var(--white);
}

.btn-container {
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
}

@media (min-width: 760px) {
  .btn-container {
    flex-direction: row;
  }
}

#result {
  margin-top: 15px;
  font-size: 1.2rem;
  line-height: 30px;
}

.btn {
  cursor: pointer;
  width: 200px;
  margin: 10px 0 10px 0.5rem;
  color: var(--black);
  background-color: var(--gold);
  background-image: linear-gradient(var(--golden-yellow), var(--orange));
  border-color: var(--gold);
  border-width: 3px;
}

.btn:hover {
  background-image: linear-gradient(var(--yellow), var(--dark-orange));
}

